{"path": "/tmp/sv-eae57c7f3c1a4adebced06bde42c8ce3/Components/Pages/Settings.razor", "file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_eae57c7f3c1a4adebced06bde42c8ce3.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h3 class="sidebar-title">Settings</h3>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span class="nav-label">@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner"></div>
                <p>Loading settings…</p>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ───── Confirmation Dialog ───── *@
@if (_confirmDialogVisible)
{
    <div class="dialog-overlay" @onclick="CancelConfirmDialog">
        <div class="dialog-box" @onclick:stopPropagation="true">
            <h4>@_confirmDialogTitle</h4>
            <p>@_confirmDialogMessage</p>
            <div class="dialog-actions">
                <button class="btn-secondary" @onclick="CancelConfirmDialog">Cancel</button>
                <button class="btn-danger" @onclick="ConfirmDialogAction">Confirm</button>
            </div>
        </div>
    </div>
}

@code {
    // ── Section navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"]       = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"]      = ("Security", "🔒"),
        ["appearance"]    = ("Appearance", "🎨"),
    };

    private bool _loading = true;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private bool _profileSaving;

    // ── Notifications state ──
    private NotificationPrefs? _savedNotifPrefs;
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private List<ChannelMuteState> _channels = new();
    private bool _notifSaving;

    private class ChannelMuteState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }

    // ── Security state ──
    private SecuritySettings? _security;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _passwordSaving;
    private bool _twoFactorEnabled;

    // ── Appearance state ──
    private AppearanceSettings? _savedAppearance;
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _appearanceSaving;

    private readonly string[] _availableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    // ── Toast ──
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Confirmation dialog ──
    private bool _confirmDialogVisible;
    private string _confirmDialogTitle = "";
    private string _confirmDialogMessage = "";
    private Func<Task>? _confirmDialogAction;

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync("profile");
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (ActiveSection == section) return;
        ActiveSection = section;
        _loading = true;
        StateHasChanged();

        await LoadSectionDataAsync(section);
        _loading = false;
    }

    private async Task LoadSectionDataAsync(string section)
    {
        switch (section)
        {
            case "profile":
                _savedProfile = await SettingsService.GetProfileAsync();
                ResetProfileFields();
                break;
            case "notifications":
                _savedNotifPrefs = await SettingsService.GetNotificationPrefsAsync();
                ResetNotifFields();
                break;
            case "security":
                _security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _security.TwoFactorEnabled;
                _changePasswordExpanded = false;
                ClearPasswordFields();
                break;
            case "appearance":
                _savedAppearance = await SettingsService.GetAppearanceAsync();
                ResetAppearanceFields();
                break;
        }
    }

    // ── Profile helpers ──
    private void ResetProfileFields()
    {
        if (_savedProfile is null) return;
        _profileDisplayName = _savedProfile.DisplayName;
        _profileEmail = _savedProfile.Email;
        _profileAvatarUrl = _savedProfile.AvatarUrl;
        _profileBio = _savedProfile.Bio;
    }

    private async Task SaveProfile()
    {
        _profileSaving = true;
        try
        {
            var updated = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            await ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally
        {
            _profileSaving = false;
        }
    }

    private void DiscardProfileChanges() => ResetProfileFields();

    // ── Notification helpers ──
    private void ResetNotifFields()
    {
        if (_savedNotifPrefs is null) return;
        _notifEmail = _savedNotifPrefs.EmailNotifications;
        _notifPush = _savedNotifPrefs.PushNotifications;
        _notifWeeklyDigest = _savedNotifPrefs.WeeklyDigest;
        _channels = _savedNotifPrefs.MutedChannels
            .Select(c => new ChannelMuteState { Name = c, Muted = true })
            .ToList();
    }

    private async Task SaveNotifications()
    {
        _notifSaving = true;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _savedNotifPrefs = updated;
            await ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _notifSaving = false;
        }
    }

    // ── Security helpers ──
    private void ClearPasswordFields()
    {
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private async Task ChangePassword()
    {
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New password and confirmation do not match.", isError: true);
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("New password cannot be empty.", isError: true);
            return;
        }

        _passwordSaving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            ClearPasswordFields();
            _changePasswordExpanded = false;
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Password change failed: {ex.Message}", isError: true);
        }
        finally
        {
            _passwordSaving = false;
        }
    }

    private void RequestRevokeSession(ActiveSession session)
    {
        _confirmDialogTitle = "Revoke Session";
        _confirmDialogMessage = $"Are you sure you want to revoke the session on \"{session.Device}\" in {session.Location}?";
        _confirmDialogAction = async () =>
        {
            await SettingsService.RevokeSessionAsync(session.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = _security.TwoFactorEnabled;
            await ShowToast("Session revoked.");
        };
        _confirmDialogVisible = true;
    }

    private async Task ConfirmDialogAction()
    {
        _confirmDialogVisible = false;
        if (_confirmDialogAction is not null)
        {
            try
            {
                await _confirmDialogAction();
            }
            catch (Exception ex)
            {
                await ShowToast($"Action failed: {ex.Message}", isError: true);
            }
        }
    }

    private void CancelConfirmDialog() => _confirmDialogVisible = false;

    // ── Appearance helpers ──
    private void ResetAppearanceFields()
    {
        if (_savedAppearance is null) return;
        _theme = _savedAppearance.Theme;
        _fontSize = _savedAppearance.FontSize;
        _language = _savedAppearance.Language;
        _compactMode = _savedAppearance.CompactMode;
    }

    private async Task SaveAppearance()
    {
        _appearanceSaving = true;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _savedAppearance = updated;
            await ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _appearanceSaving = false;
        }
    }

    // ── Toast ──
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Render fragments ──
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Profile</h2>

            <div class="avatar-area">
                @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                {
                    <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-preview" />
                }
                else
                {
                    <div class="avatar-placeholder">No Avatar</div>
                }
                <div class="form-group">
                    <label>Avatar URL</label>
                    <input type="url" @bind="_profileAvatarUrl" placeholder="https://example.com/avatar.png" />
                </div>
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_profileDisplayName" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_profileEmail" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea rows="4" @bind="_profileBio"></textarea>
            </div>

            <div class="button-row">
                <button class="btn-primary" @onclick="SaveProfile" disabled="@_profileSaving">
                    @(_profileSaving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Notifications</h2>

            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Email Notifications</span>
                    <input type="checkbox" @bind="_notifEmail" class="toggle-switch" />
                </label>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Push Notifications</span>
                    <input type="checkbox" @bind="_notifPush" class="toggle-switch" />
                </label>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Weekly Digest</span>
                    <input type="checkbox" @bind="_notifWeeklyDigest" class="toggle-switch" />
                </label>
            </div>

            @if (_channels.Count > 0)
            {
                <h3>Muted Channels</h3>
                <div class="channel-list">
                    @foreach (var channel in _channels)
                    {
                        <label class="channel-item">
                            <input type="checkbox" @bind="channel.Muted" />
                            <span>@channel.Name</span>
                        </label>
                    }
                </div>
            }

            <div class="button-row">
                <button class="btn-primary" @onclick="SaveNotifications" disabled="@_notifSaving">
                    @(_notifSaving ? "Saving…" : "Save Preferences")
                </button>
            </div>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h2>Security</h2>

            @* ── Change Password Panel ── *@
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>Change Password</span>
                    <span class="chevron @(_changePasswordExpanded ? "open" : "")">▸</span>
                </button>

                @if (_changePasswordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label>Confirm New Password</label>
                            <input type="password" @bind="_confirmPassword" />
                        </div>
                        <button class="btn-primary" @onclick="ChangePassword" disabled="@_passwordSaving">
                            @(_passwordSaving ? "Updating…" : "Update Password")
                        </button>
                    </div>
                }
            </div>

            @* ── Two-Factor Authentication ── *@
            <div class="toggle-row two-factor-row">
                <label class="toggle-label">
                    <span>
                        Two-Factor Authentication
                        <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </span>
                    <input type="checkbox" @bind="_twoFactorEnabled" class="toggle-switch" />
