toolArgs.file_text:
/* ── Layout ── */
.settings-dashboard {
    display: flex;
    min-height: 80vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    color: #495057;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.sidebar-nav li {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-weight: 500;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav li:hover {
    background: #e9ecef;
}

.sidebar-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

/* ── Section ── */
.settings-section h2 {
    margin: 0 0 1.5rem;
    font-size: 1.5rem;
    font-weight: 600;
    color: #212529;
}

.settings-section h3 {
    margin: 1.5rem 0 0.75rem;
    font-size: 1.1rem;
    font-weight: 600;
    color: #495057;
}

/* ── Forms ── */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    color: #495057;
    font-size: 0.9rem;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="url"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    max-width: 480px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    color: #212529;
    background: #fff;
    transition: border-color 0.15s;
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

/* ── Buttons ── */
.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn-primary {
    padding: 0.5rem 1.25rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-primary:disabled {
    opacity: 0.65;
    cursor: not-allowed;
}

.btn-secondary {
    padding: 0.5rem 1.25rem;
    background: #fff;
    color: #495057;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-secondary:hover {
    background: #e9ecef;
}

.btn-danger {
    padding: 0.5rem 1.25rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-danger:hover {
    background: #bb2d3b;
}

.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.85rem;
}

/* ── Avatar ── */
.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.25rem;
    margin-bottom: 1.25rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-placeholder {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.75rem;
    color: #6c757d;
    flex-shrink: 0;
}

.avatar-area .form-group {
    flex: 1;
    margin-bottom: 0;
}

/* ── Toggle switches ── */
.toggle-row {
    margin-bottom: 0.75rem;
}

.toggle-label {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: 480px;
    cursor: pointer;
    font-weight: 500;
    color: #495057;
}

.toggle-switch {
    width: 44px;
    height: 24px;
    appearance: none;
    -webkit-appearance: none;
    background: #ced4da;
    border-radius: 12px;
    position: relative;
    cursor: pointer;
    transition: background 0.2s;
    flex-shrink: 0;
}

.toggle-switch::before {
    content: '';
    position: absolute;
    top: 2px;
    left: 2px;
    width: 20px;
    height: 20px;
    border-radius: 50%;
    background: #fff;
    transition: transform 0.2s;
}

.toggle-switch:checked {
    background: #0d6efd;
}

.toggle-switch:checked::before {
    transform: translateX(20px);
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    max-width: 480px;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 400;
    color: #495057;
}

.channel-item:hover {
    background: #f8f9fa;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 1rem;
    max-width: 480px;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
    color: #212529;
    font-size: 0.95rem;
}

.panel-header:hover {
    background: #e9ecef;
}

.chevron {
    transition: transform 0.2s;
    font-size: 0.85rem;
}

.chevron.open {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Status badges ── */
.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-left: 0.5rem;
    vertical-align: middle;
}

.status-on {
    background: #d1e7dd;
    color: #0f5132;
}

.status-off {
    background: #f8d7da;
    color: #842029;
}

.current-badge {
    display: inline-block;
    padding: 0.1rem 0.4rem;
    border-radius: 8px;
    font-size: 0.7rem;
    font-weight: 600;
    background: #cfe2ff;
    color: #084298;
    margin-left: 0.4rem;
